import React, {useEffect, useRef, useState} from 'react';
import {Animated, Easing, type LayoutChangeEvent, StyleSheet, Text, View} from 'react-native';
import type {ICollapseProps} from '@lmb-it/kitsconcerto-types'


const Collapse: React.FC<ICollapseProps> = ({isOpen, children, duration = 300}) => {
    const [contentHeight, setContentHeight] = useState(0); // measured height
    const [measured, setMeasured] = useState(false);
    const animatedHeight = useRef(new Animated.Value(0)).current;

    useEffect(() => {
        if (measured) {
            Animated.timing(animatedHeight, {
                toValue: isOpen ? contentHeight : 0,
                duration,
                easing: Easing.ease,
                useNativeDriver: false,
            }).start();
        }
    }, [isOpen, contentHeight, duration, measured]);

    const onLayoutContent = (e: LayoutChangeEvent) => {
        const height = e.nativeEvent.layout.height;
        if (!measured || height !== contentHeight) {
            setContentHeight(height);
            if (!measured) setMeasured(true);
        }
    };

    const isText = typeof children === 'string'

    return (
        <Animated.View style={[styles.container, { height: animatedHeight }]}>
            <View style={styles.inner} onLayout={onLayoutContent}>
                {isText ? <Text>{children}</Text> : children}
            </View>
        </Animated.View>
    );
};

const styles = StyleSheet.create({
    container: {
        overflow: 'hidden',
    },
    inner: {
        position: 'absolute',
        width: '100%',
    },
});

export default Collapse;
